// Build sheet title and configuration payload
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const now = new Date();
const dateStr = now.toLocaleDateString('en-CA', { timeZone: tz }); // YYYY-MM-DD
const displayDate = now.toLocaleDateString('en-IN', {
  timeZone: tz, day: '2-digit', month: 'long', year: 'numeric'
}); // e.g. 15 April 2026

const sheetTitle = `Patient Intake - ${dateStr}`;
const folderId = $env.GOOGLE_DRIVE_FOLDER_ID || '';
const clinicEmail = $env.CLINIC_EMAIL || 'clinic@example.com';

// Parse dropdown values from env
const hospitalNames = ($env.CLINIC_HOSPITAL_NAMES || 'City Hospital,General Hospital,Metro Clinic')
  .split(',').map(s => s.trim()).filter(Boolean);
const doctorNames = ($env.CLINIC_DOCTOR_NAMES || 'Dr. Sharma,Dr. Mehta,Dr. Patel,Dr. Kumar')
  .split(',').map(s => s.trim()).filter(Boolean);

return [{
  json: {
    sheetTitle,
    dateStr,
    displayDate,
    folderId,
    clinicEmail,
    hospitalNames,
    doctorNames
  }
}];

// Build the full Sheets API batchUpdate request to:
// 1. Add headers to row 1
// 2. Freeze row 1
// 3. Apply data validation dropdowns
// 4. Apply conditional formatting on status column
// 5. Protect id, status, created_at, updated_at columns
// 6. Format phone column as plain text

const config = $('Build Sheet Config').first().json;
const spreadsheetId = $('Create Spreadsheet in Drive').first().json.id;
const sheetId = 0; // First sheet always has sheetId = 0

const hospitalNames = config.hospitalNames;
const doctorNames = config.doctorNames;

// Column indices (0-based): A=0, B=1, C=2, D=3, E=4, F=5, G=6, H=7, I=8, J=9, K=10, L=11, M=12
const COL = { id:0, hospital:1, doctor:2, patient_name:3, dob:4, sex:5, phone:6, visit_date:7, fu_required:8, fu_date:9, status:10, created_at:11, updated_at:12 };

// Helper: cell range object
const range = (r1, c1, r2, c2) => ({
  sheetId,
  startRowIndex: r1,
  endRowIndex: r2,
  startColumnIndex: c1,
  endColumnIndex: c2
});

// Helper: ONE_OF_LIST validation
const dropdown = (values) => ({
  condition: {
    type: 'ONE_OF_LIST',
    values: values.map(v => ({ userEnteredValue: v }))
  },
  showCustomUi: true,
  strict: true
});

const requests = [
  // ── 1. Set column headers in row 1 ───────────────────────────────────────
  {
    updateCells: {
      range: range(0, 0, 1, 13),
      rows: [{
        values: [
          { userEnteredValue: { stringValue: 'id' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'hospital_name' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'doctor_name' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'patient_name' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'dob' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'sex' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'phone_number' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'visit_date' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'follow_up_required' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'follow_up_date' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'status' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'created_at' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } },
          { userEnteredValue: { stringValue: 'updated_at' },
            userEnteredFormat: { backgroundColor: { red: 0.18, green: 0.32, blue: 0.57 },
              textFormat: { bold: true, foregroundColor: { red: 1, green: 1, blue: 1 }, fontSize: 10 } } }
        ]
      }],
      fields: 'userEnteredValue,userEnteredFormat.backgroundColor,userEnteredFormat.textFormat'
    }
  },

  // ── 2. Freeze row 1 ──────────────────────────────────────────────────────
  {
    updateSheetProperties: {
      properties: {
        sheetId,
        gridProperties: { frozenRowCount: 1 }
      },
      fields: 'gridProperties.frozenRowCount'
    }
  },

  // ── 3. Format phone column G as plain text ───────────────────────────────
  {
    repeatCell: {
      range: range(1, COL.phone, 1000, COL.phone + 1),
      cell: { userEnteredFormat: { numberFormat: { type: 'TEXT' } } },
      fields: 'userEnteredFormat.numberFormat'
    }
  },

  // ── 4. Data validation — hospital_name (column B) ─────────────────────────
  {
    setDataValidation: {
      range: range(1, COL.hospital, 1000, COL.hospital + 1),
      rule: dropdown(hospitalNames)
    }
  },

  // ── 5. Data validation — doctor_name (column C) ───────────────────────────
  {
    setDataValidation: {
      range: range(1, COL.doctor, 1000, COL.doctor + 1),
      rule: dropdown(doctorNames)
    }
  },

  // ── 6. Data validation — sex (column F) ───────────────────────────────────
  {
    setDataValidation: {
      range: range(1, COL.sex, 1000, COL.sex + 1),
      rule: dropdown(['Male', 'Female', 'Other'])
    }
  },

  // ── 7. Data validation — follow_up_required (column I) ───────────────────
  {
    setDataValidation: {
      range: range(1, COL.fu_required, 1000, COL.fu_required + 1),
      rule: dropdown(['Yes', 'No'])
    }
  },

  // ── 8. Data validation — status (column K) ────────────────────────────────
  {
    setDataValidation: {
      range: range(1, COL.status, 1000, COL.status + 1),
      rule: dropdown(['Pending', 'Completed', 'Missed'])
    }
  },

  // ── 9. Conditional formatting — status Pending = yellow ──────────────────
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [range(1, COL.status, 1000, COL.status + 1)],
        booleanRule: {
          condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Pending' }] },
          format: { backgroundColor: { red: 1, green: 0.95, blue: 0.6 } }
        }
      },
      index: 0
    }
  },

  // ── 10. Conditional formatting — status Completed = green ─────────────────
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [range(1, COL.status, 1000, COL.status + 1)],
        booleanRule: {
          condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Completed' }] },
          format: { backgroundColor: { red: 0.71, green: 0.84, blue: 0.66 } }
        }
      },
      index: 1
    }
  },

  // ── 11. Conditional formatting — status Missed = red ─────────────────────
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [range(1, COL.status, 1000, COL.status + 1)],
        booleanRule: {
          condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Missed' }] },
          format: { backgroundColor: { red: 0.96, green: 0.8, blue: 0.8 } }
        }
      },
      index: 2
    }
  },

  // ── 12. Conditional formatting — phone_number not 10 digits = orange ──────
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [range(1, COL.phone, 1000, COL.phone + 1)],
        booleanRule: {
          condition: {
            type: 'CUSTOM_FORMULA',
            values: [{ userEnteredValue: '=AND(G2<>"",OR(LEN(G2)<>10,NOT(ISNUMBER(VALUE(G2)))))' }]
          },
          format: { backgroundColor: { red: 1, green: 0.72, blue: 0.42 } }
        }
      },
      index: 3
    }
  },

  // ── 13. Protect column A (id) — written only by WF10 ─────────────────────
  {
    addProtectedRange: {
      protectedRange: {
        range: range(1, COL.id, 1000, COL.id + 1),
        description: 'Auto-generated by WF10 — do not edit',
        warningOnly: true
      }
    }
  },

  // ── 14. Protect column L (created_at) ─────────────────────────────────────
  {
    addProtectedRange: {
      protectedRange: {
        range: range(1, COL.created_at, 1000, COL.created_at + 1),
        description: 'Auto-generated by WF10 — do not edit',
        warningOnly: true
      }
    }
  },

  // ── 15. Protect column M (updated_at) ─────────────────────────────────────
  {
    addProtectedRange: {
      protectedRange: {
        range: range(1, COL.updated_at, 1000, COL.updated_at + 1),
        description: 'Auto-updated by automation — do not edit',
        warningOnly: true
      }
    }
  },

  // ── 16. Set column widths for readability ──────────────────────────────────
  {
    updateDimensionProperties: {
      range: { sheetId, dimension: 'COLUMNS', startIndex: 0, endIndex: 1 },
      properties: { pixelSize: 100 },
      fields: 'pixelSize'
    }
  },
  {
    updateDimensionProperties: {
      range: { sheetId, dimension: 'COLUMNS', startIndex: 1, endIndex: 4 },
      properties: { pixelSize: 160 },
      fields: 'pixelSize'
    }
  },
  {
    updateDimensionProperties: {
      range: { sheetId, dimension: 'COLUMNS', startIndex: 6, endIndex: 7 },
      properties: { pixelSize: 130 },
      fields: 'pixelSize'
    }
  }
];

return [{
  json: {
    spreadsheetId,
    requests
  }
}];
